#include <iostream>
#include <vector>

int main() {
    std::vector<int> numbers = {10, 20, 30, 40, 50};
    int sum = 0;

    for (int num : numbers) {
        sum += num;
    }

    std::cout << "Total sum: " << sum << std::endl;
    std::cout << "Average: " << (float)sum / numbers.size() << std::endl;
    return 0;
}

#include <iostream>
#include <memory>

class Node {
public:
    int data;
    std::shared_ptr<Node> next;

    Node(int val) : data(val), next(nullptr) {
        std::cout << "Node created with value: " << data << std::endl;
    }
    ~Node() {
        std::cout << "Node destroyed with value: " << data << std::endl;
    }
};

int main() {
    auto head = std::make_shared<Node>(1);
    head->next = std::make_shared<Node>(2);
    return 0;
}

#include <iostream>
#include <string>

class Animal {
protected:
    std::string name;
public:
    Animal(std::string n) : name(n) {}
    virtual void makeSound() = 0;
};

class Dog : public Animal {
public:
    Dog(std::string n) : Animal(n) {}
    void makeSound() override {
        std::cout << name << " says: Woof!" << std::endl;
    }
};

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::vector<int> data = {5, 2, 8, 1, 9, 3};

    std::sort(data.begin(), data.end(), [](int a, int b) {
        return a > b;
    });

    for(auto it = data.begin(); it != data.end(); ++it) {
        std::cout << *it << " ";
    }
    std::cout << std::endl;
    return 0;
}

#include <iostream>
using namespace std;

bool isEven(int number) {
    return number % 2 == 0;
}

int main() {
    for (int i = 1; i <= 10; i++) {
        if (isEven(i)) {
            cout << i << " is even\n";
        } else {
            cout << i << " is odd\n";
        }
    }
    return 0;
}

#include <iostream>
#include <map>

int main() {
    std::map<std::string, int> ages;
    ages["Alice"] = 25;
    ages["Bob"] = 30;
    ages["Charlie"] = 22;

    for (const auto& pair : ages) {
        std::cout << pair.first << " is " 
                  << pair.second << " years old.\n";
    }
    return 0;
}

#include <iostream>
#include <thread>
#include <mutex>

std::mutex mtx;

void printTask(int id) {
    std::lock_guard<std::mutex> lock(mtx);
    std::cout << "Task " << id << " is running on thread " 
              << std::this_thread::get_id() << std::endl;
}

int main() {
    std::thread t1(printTask, 1);
    std::thread t2(printTask, 2);

    t1.join();
    t2.join();
    return 0;
}
